/// Circuit state for one processing channel (nodal solver).
///
/// Contains per-sample state and sample-rate-dependent matrices.
/// Call [`set_sample_rate`](CircuitState::set_sample_rate) before processing
/// if the host sample rate differs from [`SAMPLE_RATE`].
#[derive(Clone, Debug)]
pub struct CircuitState {
    /// Previous node voltages v[n-1]
    pub v_prev: [f64; N],

    /// Previous nonlinear currents i_nl[n-1]
    pub i_nl_prev: [f64; M],

    /// Nonlinear currents from two samples ago i_nl[n-2] (for NR predictor)
    pub i_nl_prev_prev: [f64; M],

    /// DC operating point (for reset/sleep/wake)
    pub dc_operating_point: [f64; N],

    /// Previous input sample for trapezoidal integration
    pub input_prev: f64,

    /// NR convergence diagnostic from the last sample's solve.
    ///
    /// Semantics:
    /// - 0..MAX_ITER-1: 0-indexed iteration at which convergence was detected
    ///   (i.e. `last_nr_iterations + 1` iterations actually ran)
    /// - MAX_ITER: loop exhausted without convergence → NR failed
    ///
    /// The check `last_nr_iterations >= MAX_ITER` is the BE-fallback trigger;
    /// storing `iter` (not `iter + 1`) is intentional so that convergence at
    /// the final permitted iteration (iter == MAX_ITER - 1) does not false-trigger.
    pub last_nr_iterations: u32,

    /// DC blocking filter: previous input samples (one per output)
    pub dc_block_x_prev: [f64; NUM_OUTPUTS],
    /// DC blocking filter: previous output samples (one per output)
    pub dc_block_y_prev: [f64; NUM_OUTPUTS],
    /// DC blocking filter coefficient (recomputed on sample rate change)
    pub dc_block_r: f64,

    /// Diagnostic: peak absolute output (pre-clamp)
    pub diag_peak_output: f64,
    /// Diagnostic: number of times output exceeded the ±output_clamp_v ceiling
    pub diag_clamp_count: u64,
    /// Diagnostic: number of times NR hit max iterations
    pub diag_nr_max_iter_count: u64,
    /// Diagnostic: number of backward Euler fallback activations
    pub diag_be_fallback_count: u64,
    /// Diagnostic: number of times NaN triggered state reset
    pub diag_nan_reset_count: u64,
    /// Diagnostic: number of samples that needed adaptive sub-stepping
    pub diag_substep_count: u64,
    /// Diagnostic: number of LU refactorizations performed
    pub diag_refactor_count: u64,
    /// Diagnostic: number of samples hit by the global voltage-damping
    /// safety net. This is a legacy safeguard that scales v_new toward
    /// v_prev when any node moves more than ~2V (or 5% of max DC OP) in
    /// one sample. Per CLAUDE.md, output limiting must never mask solver
    /// bugs — treat a nonzero count here as a signal that the solver needs
    /// investigation, not as an acceptable steady-state.
    pub diag_voltage_damp_count: u64,

    // --- Cross-timestep chord method state (persisted LU factors) ---
    /// LU-factored Jacobian from previous convergence (chord method)
    pub chord_lu: [[f64; N]; N],
    /// Row equilibration scaling from LU factorization
    pub chord_dr: [f64; N],
    /// Column equilibration scaling from LU factorization
    pub chord_dc: [f64; N],
    /// Row permutation from LU factorization
    pub chord_perm: [usize; N],
    /// Device Jacobian consistent with chord_lu (for companion RHS)
    pub chord_j_dev: [f64; M * M],
    /// Whether chord LU factors are valid (false until first convergence)
    pub chord_valid: bool,

    /// A matrix: G + alpha*C (trapezoidal), recomputed by set_sample_rate
    pub a: [[f64; N]; N],
    /// A_neg matrix: alpha*C - G (trapezoidal history), recomputed by set_sample_rate
    pub a_neg: [[f64; N]; N],
    /// A_be matrix: G + (1/T)*C (backward Euler), recomputed by set_sample_rate
    pub a_be: [[f64; N]; N],
    /// A_neg_be matrix: (1/T)*C (backward Euler history), recomputed by set_sample_rate
    pub a_neg_be: [[f64; N]; N],
    /// S matrix: A^{-1} (trapezoidal), recomputed by set_sample_rate
    pub s: [[f64; N]; N],
    /// K matrix: N_v * S * N_i (nonlinear kernel), recomputed by set_sample_rate
    pub k: [[f64; M]; M],
    /// S_NI matrix: S * N_i (voltage recovery), recomputed by set_sample_rate
    pub s_ni: [[f64; M]; N],
    /// S_be matrix: A_be^{-1} (backward Euler), recomputed by set_sample_rate
    pub s_be: [[f64; N]; N],
    /// K_be matrix: N_v * S_be * N_i (BE kernel), recomputed by set_sample_rate
    pub k_be: [[f64; M]; M],
    /// S_NI_be matrix: S_be * N_i (BE voltage recovery), recomputed by set_sample_rate
    pub s_ni_be: [[f64; M]; N],
    /// S_sub matrix: (G+4C/T)^{-1} (trap at 2× rate), recomputed by set_sample_rate
    pub s_sub: [[f64; N]; N],
    /// A_neg_sub matrix: 4C/T-G (trap at 2× rate history), recomputed by set_sample_rate
    pub a_neg_sub: [[f64; N]; N],
    /// K_sub matrix: N_v*S_sub*N_i (sub-step kernel)
    pub k_sub: [[f64; M]; M],
    /// S_NI_sub matrix: S_sub*N_i (sub-step voltage recovery)
    pub s_ni_sub: [[f64; M]; N],

    // --- Runtime-adjustable device parameters ---
    /// Device 0 IS (Bjt) — runtime adjustable
    pub device_0_is: f64,
    /// Device 0 VT (Bjt) — runtime adjustable
    pub device_0_vt: f64,
    /// Device 0 BETA_F (Bjt) — runtime adjustable
    pub device_0_bf: f64,
    /// Device 0 BETA_R (Bjt) — runtime adjustable
    pub device_0_br: f64,
    /// Device 1 IS (Bjt) — runtime adjustable
    pub device_1_is: f64,
    /// Device 1 VT (Bjt) — runtime adjustable
    pub device_1_vt: f64,
    /// Device 1 BETA_F (Bjt) — runtime adjustable
    pub device_1_bf: f64,
    /// Device 1 BETA_R (Bjt) — runtime adjustable
    pub device_1_br: f64,
    /// Device 2 IS (Bjt) — runtime adjustable
    pub device_2_is: f64,
    /// Device 2 VT (Bjt) — runtime adjustable
    pub device_2_vt: f64,
    /// Device 2 BETA_F (Bjt) — runtime adjustable
    pub device_2_bf: f64,
    /// Device 2 BETA_R (Bjt) — runtime adjustable
    pub device_2_br: f64,
    /// Device 3 IS (Bjt) — runtime adjustable
    pub device_3_is: f64,
    /// Device 3 VT (Bjt) — runtime adjustable
    pub device_3_vt: f64,
    /// Device 3 BETA_F (Bjt) — runtime adjustable
    pub device_3_bf: f64,
    /// Device 3 BETA_R (Bjt) — runtime adjustable
    pub device_3_br: f64,
    /// Device 4 IS (Bjt) — runtime adjustable
    pub device_4_is: f64,
    /// Device 4 VT (Bjt) — runtime adjustable
    pub device_4_vt: f64,
    /// Device 4 BETA_F (Bjt) — runtime adjustable
    pub device_4_bf: f64,
    /// Device 4 BETA_R (Bjt) — runtime adjustable
    pub device_4_br: f64,
    /// Device 5 IS (Bjt) — runtime adjustable
    pub device_5_is: f64,
    /// Device 5 VT (Bjt) — runtime adjustable
    pub device_5_vt: f64,
    /// Device 5 BETA_F (Bjt) — runtime adjustable
    pub device_5_bf: f64,
    /// Device 5 BETA_R (Bjt) — runtime adjustable
    pub device_5_br: f64,
    /// Device 6 IS (Bjt) — runtime adjustable
    pub device_6_is: f64,
    /// Device 6 VT (Bjt) — runtime adjustable
    pub device_6_vt: f64,
    /// Device 6 BETA_F (Bjt) — runtime adjustable
    pub device_6_bf: f64,
    /// Device 6 BETA_R (Bjt) — runtime adjustable
    pub device_6_br: f64,
    /// Device 7 IS (Bjt) — runtime adjustable
    pub device_7_is: f64,
    /// Device 7 VT (Bjt) — runtime adjustable
    pub device_7_vt: f64,
    /// Device 7 BETA_F (Bjt) — runtime adjustable
    pub device_7_bf: f64,
    /// Device 7 BETA_R (Bjt) — runtime adjustable
    pub device_7_br: f64,
    /// Runtime value for voltage source V1 (RHS row 18).
    pub v_rail_pos_offset: f64,
    /// Runtime value for voltage source V2 (RHS row 19).
    pub v_rail_neg_offset: f64,
}

